#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,A1,B1,A2,B2;
        scanf("%d %d %d %d %d %d", &A,&B,&A1,&B1,&A2,&B2);
        int ans=0;
        if( (A==A1 && B==B1) || (A==B1 && B==A1) ) ans=1;
        else if( (A==A2 && B==B2) || (A==B2 && B==A2) ) ans=2;
        printf("%d\n", ans);
    }
    return 0;
}

