#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        A1 = int(next(it)); B1 = int(next(it))
        A2 = int(next(it)); B2 = int(next(it))
        if (A == A1 and B == B1) or (A == B1 and B == A1):
            out.append('1')
        elif (A == A2 and B == B2) or (A == B2 and B == A2):
            out.append('2')
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

